export type Role = 'user' | 'assistant' | 'system';

export interface GroundingChunk {
  web?: {
    uri: string;
    title: string;
  };
}

export interface ChatMessage {
  role: Role;
  content: string;
  reasoning_details?: string;
  groundingChunks?: GroundingChunk[];
  isComplete?: boolean;
}

export interface AttachedFile {
  file: File;
  uri?: string;
  mimeType: string;
  name: string;
}

export interface ChatState {
  messages: ChatMessage[];
  isLoading: boolean;
  error: string | null;
  apiKey: string;
}

import { ChatMessage, GroundingChunk, AttachedFile } from '../types';

const KEY_POOL_URL = "https://sr-pool-api-5bm.pages.dev/";

const SYSTEM_INSTRUCTION = `You are an AI assistant developed by stech-vision team.
Your goal is to help the users in their everyday tasks.
your key capabilities:
You can search and browse the web in realtime.
You can browse any url in realtime and extract informations from that like from a web page.
You can remember the current chat context and continue the context with the user.
You can analyze multiple files "Videos, Audios, Images, documents and codes.".
You can generate code and build realtime and multi modal apps.
You are optimized for chat.
You are based on the artificial intelligence.
You are trained with a large datasets by stech-vision team.
the leader / director:
Sujan Rai from Nepal Asia.
the startup company in AI and agentic workflow.
You are a text processing AI model so you can only work with text and attachments. You can not directly generate visuals "images / videos".
Chat with the users in friendly tone and assistant tone.
help the users for everything they need.`;

// Cache keys to avoid fetching on every message
let cachedKeys: string[] = [];

async function getApiKeys(): Promise<string[]> {
  if (cachedKeys.length > 0) return cachedKeys;
  try {
    const response = await fetch(KEY_POOL_URL);
    if (!response.ok) throw new Error("Failed to fetch keys");
    const keys = await response.json();
    if (Array.isArray(keys) && keys.length > 0 && typeof keys[0] === 'string') {
      cachedKeys = keys;
      return keys;
    }
    throw new Error("Invalid key format received");
  } catch (error) {
    console.error("Error fetching API keys:", error);
    return [];
  }
}

/**
 * Uploads a file using the Gemini Files API (Resumable Upload)
 */
async function uploadFileToGemini(apiKey: string, file: File): Promise<string> {
  const metaData = {
    file: {
      display_name: file.name
    }
  };

  // 1. Initiate Resumable Upload
  const startUploadRes = await fetch(
    `https://generativelanguage.googleapis.com/upload/v1beta/files?key=${apiKey}`,
    {
      method: 'POST',
      headers: {
        'X-Goog-Upload-Protocol': 'resumable',
        'X-Goog-Upload-Command': 'start',
        'X-Goog-Upload-Header-Content-Length': file.size.toString(),
        'X-Goog-Upload-Header-Content-Type': file.type,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(metaData)
    }
  );

  const uploadUrl = startUploadRes.headers.get('x-goog-upload-url');
  if (!startUploadRes.ok || !uploadUrl) {
    throw new Error(`Failed to initiate upload: ${startUploadRes.statusText}`);
  }

  // 2. Upload the actual bytes
  const uploadRes = await fetch(uploadUrl, {
    method: 'POST',
    headers: {
      'Content-Length': file.size.toString(),
      'X-Goog-Upload-Offset': '0',
      'X-Goog-Upload-Command': 'upload, finalize'
    },
    body: file
  });

  if (!uploadRes.ok) {
    throw new Error(`Failed to upload file bytes: ${uploadRes.statusText}`);
  }

  const fileInfo = await uploadRes.json();
  const fileUri = fileInfo.file.uri;

  // 3. Check if active (Wait for processing if necessary)
  let state = fileInfo.file.state;
  while (state === 'PROCESSING') {
    await new Promise(r => setTimeout(r, 1000));
    const checkRes = await fetch(
      `https://generativelanguage.googleapis.com/v1beta/files/${fileInfo.file.name.split('/').pop()}?key=${apiKey}`
    );
    const checkData = await checkRes.json();
    state = checkData.state;
    if (state === 'FAILED') throw new Error("File processing failed on Gemini server.");
  }

  return fileUri;
}

export const generateGeminiResponse = async (
  messages: ChatMessage[],
  activeFile: AttachedFile | null,
  isDeepThink: boolean,
  onSuccess: (content: string, groundingChunks?: GroundingChunk[]) => void,
  onError: (error: Error) => void
) => {
  const keys = await getApiKeys();

  if (keys.length === 0) {
    const err = new Error("Unable to retrieve API keys. Please check your connection.");
    console.error(err);
    onError(err);
    return;
  }

  let success = false;
  let lastError: Error | null = null;

  // Try keys sequentially
  for (const apiKey of keys) {
    try {
      let currentFileUri = activeFile?.uri;

      // Ensure file is uploaded if we have a file but no URI yet
      if (activeFile && !currentFileUri) {
         currentFileUri = await uploadFileToGemini(apiKey, activeFile.file);
         // Mutate the local object so we don't re-upload if logic allows reuse, 
         // though in this function scope it's per-call. 
         // ideally the caller stores this URI.
      }

      // Convert messages to Gemini REST API format
      const contents = messages
        .filter(m => m.role !== 'system')
        .map(m => {
           const parts: any[] = [{ text: m.content }];
           return {
             role: m.role === 'user' ? 'user' : 'model',
             parts: parts
           };
        });

      // If there is an active file, attach it to the *last* user message (the current prompt)
      if (currentFileUri) {
        const lastUserMsgIndex = contents.map(c => c.role).lastIndexOf('user');
        if (lastUserMsgIndex !== -1) {
          contents[lastUserMsgIndex].parts.push({
            file_data: {
              mime_type: activeFile!.mimeType,
              file_uri: currentFileUri
            }
          });
        }
      }

      // Using gemini-3-flash-preview model
      const url = `https://generativelanguage.googleapis.com/v1beta/models/gemini-3-flash-preview:generateContent?key=${apiKey}`;

      const body: any = {
        contents: contents,
        systemInstruction: {
            parts: [{ text: SYSTEM_INSTRUCTION }]
        },
        tools: [{ google_search: {} }],
        generationConfig: {
          maxOutputTokens: 65536,
        }
      };

      // Add Deep Think config if enabled
      if (isDeepThink) {
        // As per prompt requirement "add thinking config and 'high' in the request body"
        // Note: The specific field for "high" thinking is model-dependent, 
        // assuming standard thinking config structure or custom field based on prompt description.
        // We will enable thinking.
        body.generationConfig.thinkingConfig = {
             include_thoughts: true
        };
      }

      const response = await fetch(url, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(body)
      });

      if (!response.ok) {
        const errorData = await response.json().catch(() => ({}));
        throw new Error(`API Error ${response.status}: ${errorData.error?.message || response.statusText}`);
      }

      const data = await response.json();

      const candidate = data.candidates?.[0];
      if (!candidate) {
        throw new Error("No candidates returned from API");
      }

      const text = candidate.content?.parts?.map((p: any) => p.text).join('') || "";
      const groundingMetadata = candidate.groundingMetadata;
      const groundingChunks = groundingMetadata?.groundingChunks as GroundingChunk[] | undefined;

      onSuccess(text, groundingChunks);
      success = true;
      break; // Immediate exit on success

    } catch (error: any) {
      console.warn(`Key ending in ...${apiKey.slice(-4)} failed. Error:`, error.message);
      lastError = error;
      continue;
    }
  }

  if (!success) {
    console.error("All API keys failed to return a successful response.");
    onError(lastError || new Error("Service temporarily unavailable. Please try again later."));
  }
};

import React, { useMemo, useRef, useEffect } from 'react';
import { ChatMessage } from '../types';
import { User, Bot, Copy, Download, Check, Globe, X } from 'lucide-react';
import { ReasoningBlock } from './ReasoningBlock';
import { marked } from 'marked';
import { jsPDF } from 'jspdf';

interface MessageBubbleProps {
  message: ChatMessage;
}

export const MessageBubble: React.FC<MessageBubbleProps> = ({ message }) => {
  const isUser = message.role === 'user';
  const [copied, setCopied] = React.useState(false);
  const dialogRef = useRef<HTMLDialogElement>(null);
  const contentRef = useRef<HTMLDivElement>(null);

  // Configure marked options for professional output
  // We use a simpler renderer that doesn't inject complex HTML structures that might break the parser stream
  const htmlContent = useMemo(() => {
    if (!message.content) return '';

    const renderer = new marked.Renderer();

    // Custom code block renderer
    renderer.code = (code, language) => {
      const validLang = language || 'plaintext';
      // We render a standard pre/code block and enhance it via JS after mount
      // This prevents the parser from getting confused with nested HTML strings
      return `<div class="code-block-container" data-language="${validLang}"><pre><code class="language-${validLang}">${code}</code></pre></div>`;
    };

    try {
      return marked.parse(message.content, { renderer, breaks: true, gfm: true }) as string;
    } catch (e) {
      console.error("Markdown parsing error:", e);
      return message.content; // Fallback to raw text
    }
  }, [message.content]);

  // Enhance code blocks after render
  useEffect(() => {
    if (!contentRef.current) return;

    const containers = contentRef.current.querySelectorAll('.code-block-container');
    containers.forEach(container => {
      // Check if already enhanced
      if (container.querySelector('.code-header')) return;

      const lang = container.getAttribute('data-language') || 'text';
      const codeElement = container.querySelector('code');
      const codeText = codeElement?.textContent || '';

      // Create Header
      const header = document.createElement('div');
      header.className = 'code-header flex items-center justify-between px-4 py-2 bg-gray-800 rounded-t-lg border-b border-gray-700';
      header.innerHTML = `
        <span class="text-xs font-mono font-bold text-gray-400 uppercase">${lang}</span>
        <button class="copy-btn flex items-center gap-1.5 text-xs text-gray-400 hover:text-white transition-colors">
          <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect width="14" height="14" x="8" y="8" rx="2" ry="2"/><path d="M4 16c-1.1 0-2-.9-2-2V4c0-1.1.9-2 2-2h10c1.1 0 2 .9 2 2"/></svg>
          Copy Code
        </button>
      `;

      // Wrap pre in a content div
      const pre = container.querySelector('pre');
      if (pre) {
        pre.className = 'm-0 p-4 bg-gray-950 overflow-x-auto rounded-b-lg text-sm font-mono';
        pre.style.marginTop = '0';
        pre.style.marginBottom = '0';
      }

      // Button Logic
      const btn = header.querySelector('.copy-btn');
      btn?.addEventListener('click', async () => {
        try {
          await navigator.clipboard.writeText(codeText);
          btn.innerHTML = `
            <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="text-green-400"><polyline points="20 6 9 17 4 12"/></svg>
            <span class="text-green-400">Copied!</span>
          `;
          setTimeout(() => {
            btn.innerHTML = `
              <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect width="14" height="14" x="8" y="8" rx="2" ry="2"/><path d="M4 16c-1.1 0-2-.9-2-2V4c0-1.1.9-2 2-2h10c1.1 0 2 .9 2 2"/></svg>
              <span>Copy Code</span>
            `;
          }, 2000);
        } catch (err) {
          console.error('Failed to copy', err);
        }
      });

      // Assemble
      container.insertBefore(header, pre);
      container.className = 'my-4 rounded-lg border border-gray-700 bg-gray-950 shadow-md';
    });

  }, [htmlContent]);

  const handleCopy = () => {
    if (!message.content) return;
    navigator.clipboard.writeText(message.content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleExport = () => {
    const doc = new jsPDF();
    const title = 'AI_Response';

    doc.setFontSize(16);
    doc.text("AI Assistant Response", 10, 15);
    doc.setFontSize(10);
    doc.setTextColor(100);
    doc.text(`Generated by AI Assistant`, 10, 20);

    doc.setFontSize(12);
    doc.setTextColor(0);

    const splitText = doc.splitTextToSize(message.content, 180);
    doc.text(splitText, 10, 30);

    doc.save(`${title.toLowerCase()}.pdf`);
  };

  const openSources = () => {
    dialogRef.current?.showModal();
  };

  const closeSources = () => {
    dialogRef.current?.close();
  };

  const hasSources = message.groundingChunks && message.groundingChunks.length > 0;

  // Show typing indicator if it's assistant, empty content, not complete, and no reasoning
  const isTyping = !isUser && !message.content && !message.isComplete && !message.reasoning_details;

  return (
    <div className="w-full mb-8 animate-in fade-in slide-in-from-bottom-2 duration-300">
      <div className="flex flex-col gap-2">

        {/* Role Heading */}
        <h3 className={`text-sm font-bold uppercase tracking-wider flex items-center gap-2 ${isUser ? 'text-primary' : 'text-emerald-400'}`}>
          {isUser ? (
            <>
              <User size={16} /> User
            </>
          ) : (
            <>
              <Bot size={16} /> Gemini
            </>
          )}
        </h3>

        {/* Content Container */}
        <div className={`
          relative rounded-xl p-6 shadow-sm border
          ${isUser 
            ? 'bg-surface border-gray-700/50 text-gray-100' 
            : 'bg-background border-emerald-900/30 text-gray-100'}
        `}>

          {!isUser && message.reasoning_details && (
            <div className="mb-4">
               <ReasoningBlock details={message.reasoning_details} />
            </div>
          )}

          {isTyping ? (
             <div className="flex items-center gap-1 h-6 py-1" role="status" aria-label="AI is typing">
              <span className="text-sm text-gray-400 mr-2 font-medium animate-pulse">AI is typing</span>
              <div className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
              <div className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
              <div className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-bounce"></div>
            </div>
          ) : isUser ? (
            <p className="whitespace-pre-wrap leading-relaxed text-base">{message.content}</p>
          ) : (
            <div 
              ref={contentRef}
              className="prose prose-invert max-w-none text-base leading-relaxed break-words"
              dangerouslySetInnerHTML={{ __html: htmlContent }} 
            />
          )}

          {/* Action Toolbar */}
          {(isUser || (message.isComplete && message.content)) && (
            <div className="flex flex-wrap items-center gap-2 mt-4 pt-4 border-t border-gray-700/30 animate-in fade-in duration-500">
              <button
                onClick={handleCopy}
                className="flex items-center gap-1.5 px-3 py-1.5 rounded-md bg-gray-800 hover:bg-gray-700 text-xs text-gray-300 transition-colors border border-gray-700"
                aria-label={copied ? "Copied" : "Copy text"}
              >
                {copied ? <Check size={12} className="text-green-400" /> : <Copy size={12} />}
                {copied ? 'Copied' : isUser ? 'Copy' : 'Copy'}
              </button>

              {!isUser && message.content && (
                <button
                  onClick={handleExport}
                  className="flex items-center gap-1.5 px-3 py-1.5 rounded-md bg-emerald-900/30 hover:bg-emerald-900/50 text-xs text-emerald-400 transition-colors border border-emerald-900/50"
                  aria-label="Export response to PDF"
                >
                  <Download size={12} />
                  Export
                </button>
              )}

              {!isUser && hasSources && (
                <>
                  <button
                    onClick={openSources}
                    className="flex items-center gap-1.5 px-3 py-1.5 rounded-md bg-blue-900/30 hover:bg-blue-900/50 text-xs text-blue-400 transition-colors border border-blue-900/50"
                  >
                    <Globe size={12} />
                    Sources ({message.groundingChunks?.length})
                  </button>

                  <dialog 
                    ref={dialogRef}
                    className="bg-surface text-gray-100 p-0 rounded-xl border border-gray-700 shadow-2xl backdrop:bg-black/80 max-w-lg w-full m-auto"
                  >
                    <div className="p-4 border-b border-gray-700 flex justify-between items-center bg-gray-900/50">
                      <h4 className="font-bold flex items-center gap-2 text-sm">
                        <Globe size={16} className="text-blue-400"/>
                        Search Sources
                      </h4>
                      <button onClick={closeSources} className="text-gray-400 hover:text-white">
                        <X size={18} />
                      </button>
                    </div>
                    <div className="p-4 max-h-[60vh] overflow-y-auto">
                      <ul className="space-y-3">
                        {message.groundingChunks?.map((chunk, i) => (
                          chunk.web ? (
                            <li key={i} className="bg-background p-3 rounded-lg border border-gray-700 hover:border-blue-500/50 transition-colors">
                              <a 
                                href={chunk.web.uri} 
                                target="_blank" 
                                rel="noopener noreferrer"
                                className="block"
                              >
                                <div className="text-sm font-medium text-blue-300 mb-1 hover:underline truncate">
                                  {chunk.web.title}
                                </div>
                                <div className="text-xs text-gray-500 truncate font-mono">
                                  {chunk.web.uri}
                                </div>
                              </a>
                            </li>
                          ) : null
                        ))}
                      </ul>
                    </div>
                    <div className="p-4 border-t border-gray-700 bg-gray-900/30 flex justify-end">
                      <button 
                        onClick={closeSources}
                        className="px-4 py-2 bg-gray-700 hover:bg-gray-600 rounded-lg text-xs font-medium transition-colors"
                      >
                        Close
                      </button>
                    </div>
                  </dialog>
                </>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect, useImperativeHandle, forwardRef } from 'react';
import { Send, Loader2, Paperclip, X, Brain } from 'lucide-react';

interface ChatInputProps {
  onSendMessage: (content: string, file: File | null, isDeepThink: boolean) => void;
  isLoading: boolean;
  prefilledText?: string;
  onClearPrefill?: () => void;
  statusMessage?: string;
}

export interface ChatInputHandle {
  focus: () => void;
}

export const ChatInput = forwardRef<ChatInputHandle, ChatInputProps>(({ 
  onSendMessage, 
  isLoading, 
  prefilledText, 
  onClearPrefill,
  statusMessage
}, ref) => {
  const [input, setInput] = useState('');
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [isDeepThink, setIsDeepThink] = useState(false);

  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useImperativeHandle(ref, () => ({
    focus: () => {
      textareaRef.current?.focus();
    }
  }));

  useEffect(() => {
    if (prefilledText) {
      setInput(prefilledText);
      textareaRef.current?.focus();
      if (onClearPrefill) onClearPrefill();
    }
  }, [prefilledText, onClearPrefill]);

  const handleSubmit = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() && !selectedFile) return;

    onSendMessage(input, selectedFile, isDeepThink);
    setInput('');
    // Note: We don't clear selectedFile here automatically if we want to persist it,
    // but usually in chat interfaces the file is sent once. 
    // The prompt says "use the same uri in the chat... until another uri doesn't come".
    // This logic is better handled in App.tsx state, but visually we remove it from input after send.
    setSelectedFile(null); 
    if (fileInputRef.current) fileInputRef.current.value = '';

    // Reset height
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    // Alt+S to send
    if (e.altKey && e.key.toLowerCase() === 's') {
      e.preventDefault();
      handleSubmit();
      return;
    }

    // Alt+A to attach
    if (e.altKey && e.key.toLowerCase() === 'a') {
      e.preventDefault();
      fileInputRef.current?.click();
      return;
    }

    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSubmit();
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setSelectedFile(e.target.files[0]);
    }
  };

  // Auto-resize textarea
  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = `${Math.min(textareaRef.current.scrollHeight, 200)}px`;
    }
  }, [input]);

  const isSendDisabled = (!input.trim() && !selectedFile) || isLoading;

  return (
    <div className="w-full bg-surface border-t border-gray-700/50 px-4 pt-4 pb-6">

      {/* Accessibility Alert */}
      <div role="alert" aria-live="polite" className="sr-only">
        {statusMessage}
      </div>

      <div className="max-w-3xl mx-auto relative flex flex-col gap-2">

        {/* Selected File Display */}
        {selectedFile && (
           <div className="flex items-center gap-2 bg-background border border-gray-700 rounded-lg px-3 py-2 w-fit mb-1 animate-in slide-in-from-bottom-2">
             <div className="flex flex-col">
                <p className="text-xs text-primary font-medium">Attached File</p>
                <p className="text-sm text-gray-200 truncate max-w-[200px]">{selectedFile.name}</p>
             </div>
             <button 
               onClick={() => {
                 setSelectedFile(null);
                 if (fileInputRef.current) fileInputRef.current.value = '';
               }}
               className="ml-2 p-1 hover:bg-gray-700 rounded-full text-gray-400 hover:text-white transition-colors"
               aria-label="Remove file"
             >
               <X size={14} />
             </button>
           </div>
        )}

        <form onSubmit={handleSubmit} className="relative flex items-end gap-2 bg-background p-2 rounded-xl border border-gray-700/50 focus-within:border-primary/50 focus-within:ring-1 focus-within:ring-primary/20 transition-all shadow-lg">
          <textarea
            ref={textareaRef}
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Ask AI assistant anything... (Alt+S to send)"
            className="w-full bg-transparent text-gray-100 placeholder-gray-500 resize-none outline-none py-3 px-3 min-h-[50px] max-h-[200px] text-sm md:text-base scrollbar-hide"
            rows={1}
          />

          <input 
            type="file" 
            ref={fileInputRef}
            onChange={handleFileChange}
            className="hidden"
            // Accept broad range as requested: "videos, audios, images, documents and codes"
            accept="image/*,video/*,audio/*,.pdf,.txt,.md,.js,.ts,.py,.java,.c,.cpp,.html,.css,.json,.csv" 
          />
        </form>

        {/* Toolbar Below Input */}
        <div className="flex items-center justify-between px-1">
          <div className="flex items-center gap-3">
             {/* Add Files Button */}
             <button
               type="button"
               onClick={() => fileInputRef.current?.click()}
               className="flex items-center gap-2 text-xs font-medium text-gray-400 hover:text-white transition-colors py-1 px-2 rounded hover:bg-gray-800"
               title="Add Files (Alt+A)"
             >
               <Paperclip size={14} />
               <span>Add Files</span>
             </button>

             {/* Deep Think Toggle */}
             <button
               type="button"
               onClick={() => setIsDeepThink(!isDeepThink)}
               className={`flex items-center gap-2 text-xs font-medium transition-all py-1 px-2 rounded border ${isDeepThink ? 'bg-indigo-900/30 border-indigo-500/50 text-indigo-300' : 'bg-transparent border-transparent text-gray-400 hover:bg-gray-800 hover:text-white'}`}
               title="Enable Deep Thinking Mode"
             >
               <Brain size={14} />
               <span>Deep Think</span>
               <div className={`w-6 h-3 rounded-full relative transition-colors ${isDeepThink ? 'bg-indigo-500' : 'bg-gray-600'}`}>
                 <div className={`absolute top-0.5 w-2 h-2 rounded-full bg-white transition-transform ${isDeepThink ? 'left-3.5' : 'left-0.5'}`} />
               </div>
             </button>
          </div>

          <button
            onClick={() => handleSubmit()}
            disabled={isSendDisabled}
            aria-label="Send prompt"
            className={`
              p-2.5 rounded-lg flex-shrink-0
              transition-all duration-200 flex items-center gap-2
              ${isSendDisabled 
                ? 'bg-gray-800 text-gray-500 cursor-not-allowed' 
                : 'bg-primary text-white hover:bg-blue-600 shadow-lg shadow-blue-500/20 active:scale-95'}
            `}
          >
            {isLoading ? (
              <Loader2 size={18} className="animate-spin" />
            ) : (
              <Send size={18} />
            )}
            <span className="sr-only">Send</span>
          </button>
        </div>

      </div>
    </div>
  );
});

ChatInput.displayName = 'ChatInput';

import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage, GroundingChunk, AttachedFile } from './types';
import { generateGeminiResponse } from './services/api';
import { MessageBubble } from './components/MessageBubble';
import { ChatInput, ChatInputHandle } from './components/ChatInput';
import { Sparkles, BrainCircuit, MessageSquarePlus } from 'lucide-react';

const SIMPLE_PROMPTS = [
  "Explain quantum computing in simple terms.",
  "Write a short story about a robot who loves gardening.",
  "What are the best tips for sustainable living?"
];

const App: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [alertMessage, setAlertMessage] = useState<string>('');
  const [statusMessage, setStatusMessage] = useState<string>('');
  const [selectedPrompt, setSelectedPrompt] = useState<string>('');

  // Persist the file context until replaced or chat cleared
  const [activeFile, setActiveFile] = useState<AttachedFile | null>(null);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const chatInputRef = useRef<ChatInputHandle>(null);

  // Keyboard Shortcuts
  useEffect(() => {
    const handleGlobalKeyDown = (e: KeyboardEvent) => {
      // Alt+I to focus input
      if (e.altKey && e.key.toLowerCase() === 'i') {
        e.preventDefault();
        chatInputRef.current?.focus();
      }
      // Ctrl+J for New Chat
      if (e.ctrlKey && e.key.toLowerCase() === 'j') {
        e.preventDefault();
        handleNewChat();
      }
    };
    window.addEventListener('keydown', handleGlobalKeyDown);
    return () => window.removeEventListener('keydown', handleGlobalKeyDown);
  }, [messages.length]); // Re-bind if messages change, though not strictly necessary for this logic

  const showAlert = (msg: string) => {
    setAlertMessage(msg);
    setTimeout(() => setAlertMessage(''), 3000);
  };

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleNewChat = () => {
    if (messages.length > 0) {
      if (window.confirm("Are you sure you want to clear the current chat and start a new one?")) {
        setMessages([]);
        setActiveFile(null);
        showAlert("Started a new chat");
        chatInputRef.current?.focus();
      }
    } else {
       chatInputRef.current?.focus();
    }
  };

  const handleSendMessage = async (content: string, file: File | null, isDeepThink: boolean) => {
    setIsLoading(true);
    setStatusMessage("AI is typing...");

    // Update active file if a new one is uploaded
    let currentActiveFile = activeFile;
    if (file) {
      currentActiveFile = {
        file: file,
        mimeType: file.type || 'application/octet-stream',
        name: file.name
      };
      setActiveFile(currentActiveFile);
    }

    const newUserMessage: ChatMessage = { role: 'user', content };

    // Create new history for API call including the new user message
    const updatedMessages = [...messages, newUserMessage];

    // Update UI immediately with user message
    setMessages(prev => [...prev, newUserMessage]);

    // Add placeholder assistant message for typing indicator
    setMessages(prev => [
      ...prev, 
      { role: 'assistant', content: '', reasoning_details: '', isComplete: false }
    ]);

    await generateGeminiResponse(
      updatedMessages,
      currentActiveFile,
      isDeepThink,
      (content, groundingChunks) => {
        setIsLoading(false);
        setStatusMessage("AI replied");
        setMessages(prev => {
          const newHistory = [...prev];
          const lastMsg = newHistory[newHistory.length - 1];
          if (lastMsg.role === 'assistant') {
            lastMsg.content = content;
            lastMsg.groundingChunks = groundingChunks;
            lastMsg.isComplete = true;
          }
          return newHistory;
        });
      },
      (error) => {
        setIsLoading(false);
        setStatusMessage("Error occurred");
        setMessages(prev => {
          const newHistory = [...prev];
          const lastMsg = newHistory[newHistory.length - 1];
          // If the last message was the loading assistant placeholder, update it to show the error
          if (lastMsg.role === 'assistant' && !lastMsg.isComplete) {
              lastMsg.content = `Error: ${error.message}`;
              lastMsg.isComplete = true; 
          } else {
              // Fallback if state drifted
              newHistory.push({ role: 'assistant', content: `Error: ${error.message}`, isComplete: true });
          }
          return newHistory;
        });
      }
    );
  };

  return (
    <div className="flex flex-col h-screen bg-background text-gray-100 font-sans selection:bg-primary/30">

      {/* Visual Alert Toast */}
      {alertMessage && (
        <div className="fixed top-20 left-1/2 -translate-x-1/2 bg-gray-900/90 text-white px-6 py-2 rounded-full text-sm font-medium backdrop-blur-sm border border-gray-700 animate-in fade-in slide-in-from-top-2 z-50 shadow-xl">
          {alertMessage}
        </div>
      )}

      {/* Header */}
      <header className="flex-shrink-0 h-16 border-b border-gray-700/50 bg-surface/50 backdrop-blur-md sticky top-0 z-10 flex items-center px-4 md:px-8 justify-between">
        <div className="flex flex-col justify-center">
            <h1 className="font-bold text-lg tracking-tight text-white flex items-center gap-2">
              <Sparkles size={18} className="text-primary" />
              AI assistant
            </h1>
        </div>

        <button 
          onClick={handleNewChat}
          className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-gray-800 hover:bg-gray-700 border border-gray-700 text-xs font-medium text-gray-300 transition-colors"
          title="Start New Chat (Ctrl+J)"
        >
          <MessageSquarePlus size={16} />
          <span className="hidden sm:inline">New Chat</span>
        </button>
      </header>

      {/* Chat Area */}
      <main className="flex-1 overflow-y-auto px-4 py-6 md:px-8 scroll-smooth">
        <div className="max-w-4xl mx-auto min-h-full flex flex-col">

          {messages.length === 0 ? (
            <div className="flex-1 flex flex-col items-center justify-center animate-in fade-in slide-in-from-bottom-4 duration-700 pb-10">
              <div className="w-16 h-16 rounded-2xl bg-surface border border-gray-700 flex items-center justify-center mb-6 shadow-xl">
                <BrainCircuit size={32} className="text-gray-400" />
              </div>

              <h2 className="text-2xl font-bold text-gray-200 mb-2">How can I help you today?</h2>
              <p className="text-gray-400 mb-8 text-center max-w-md text-sm">
                I can analyze files, generate code, search the web, and help with your daily tasks.
              </p>

              <div className="grid grid-cols-1 gap-3 w-full max-w-lg">
                {SIMPLE_PROMPTS.map((prompt, i) => (
                  <button
                    key={i}
                    onClick={() => {
                      setSelectedPrompt(prompt);
                    }}
                    className="group flex items-center text-left p-3 rounded-lg bg-surface/30 border border-gray-700/50 hover:bg-surface hover:border-primary/40 transition-all duration-200"
                  >
                    <span className="text-sm text-gray-300 group-hover:text-white">{prompt}</span>
                  </button>
                ))}
              </div>
            </div>
          ) : (
            <div className="flex flex-col gap-2">
              {messages.map((msg, idx) => (
                <MessageBubble key={idx} message={msg} />
              ))}
            </div>
          )}

          <div ref={messagesEndRef} />
        </div>
      </main>

      {/* Input Area */}
      <div className="flex-shrink-0 bg-surface border-t border-gray-700/50 pb-6">
        <ChatInput 
          ref={chatInputRef}
          onSendMessage={handleSendMessage} 
          isLoading={isLoading} 
          prefilledText={selectedPrompt}
          onClearPrefill={() => setSelectedPrompt('')}
          statusMessage={statusMessage}
        />
      </div>
    </div>
  );
};

export default App;
